import{_ as e}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as a,o,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"项目设置","description":"","frontmatter":{},"headers":[],"relativePath":"zh/configuration/project-settings.md","filePath":"zh/configuration/project-settings.md"}'),r={name:"zh/configuration/project-settings.md"};function n(s,t,i,c,g,h){return o(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="项目设置" tabindex="-1"><i class="ph-fill ph-gear-six"></i> 项目设置 <a class="header-anchor" href="#项目设置" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; 项目设置&quot;">​</a></h1><p>所有全局 WebAP 设置都集中在一个位置：<strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+e+'" alt=""></p><h2 id="通用设置" tabindex="-1">通用设置 <a class="header-anchor" href="#通用设置" aria-label="Permalink to &quot;通用设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">性能基线。• 如果当前 FPS 降至此值以下（考虑性能余量），插件将开始降低图形质量。• 如果 FPS 始终保持在其之上，插件将尝试提高质量。<em>建议：</em> 设置合理的值。对于 WebGL，事实上的标准是 <code>60</code>，但对于繁重的 3D 项目，您可以利用 <code>30</code>。</td></tr></tbody></table><h2 id="索引器设置" tabindex="-1">索引器设置 <a class="header-anchor" href="#索引器设置" aria-label="Permalink to &quot;索引器设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">系统在<em>降低</em>质量后等待重新评估 FPS 的时间（以秒为单位）。<em>建议：</em> 应该很短（<code>1.0</code> - <code>2.0</code> 秒）。系统必须快速响应延迟并“丢弃压舱物”，直到 FPS 稳定。</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;"><em>提高</em>质量后的等待时间。<em>建议：</em> 应该很长（<code>5.0</code> - <code>10.0</code> 秒）。在再次加重系统负担之前，它必须验证先前的图形升级是否没有破坏帧的稳定性。</td></tr></tbody></table><h2 id="anti-yo-yo-惩罚系统" tabindex="-1">Anti Yo-Yo 惩罚系统 <a class="header-anchor" href="#anti-yo-yo-惩罚系统" aria-label="Permalink to &quot;Anti Yo-Yo 惩罚系统&quot;">​</a></h2><p>防止“乒乓效应”，即质量在两个级别之间无休止地切换。</p><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">在<em>增加</em>质量后系统密切监视 FPS 的时间范围。如果在此期间发生 FPS 下降，系统将其分类为 Yo-Yo 效应。</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">任何尝试<em>提高</em>质量的操作被完全阻止的惩罚持续时间（例如，<code>60</code> 秒）。</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">注意</p><p>惩罚仅会阻止增加操作。如果 FPS 再次下降，系统仍可紧急降低质量。</p></div><h2 id="缩放器-scalers" tabindex="-1">缩放器 (Scalers) <a class="header-anchor" href="#缩放器-scalers" aria-label="Permalink to &quot;缩放器 (Scalers)&quot;">​</a></h2><p>每个活动的缩放器都具有一组基线参数。这些参数决定了其对系统的“成本”。插件实时自动计算该成本：视觉影响最低且目标 (CPU/GPU) 匹配的缩放器将首先被调用。</p><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">基线和最低质量之间的离散步骤（级别）数。例如，<code>Max Level = 4</code> 意味着该缩放器具有 4 个降级步骤。</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">最小比例值（当缩放器达到其 <code>Max Level</code> 时应用）。例如，<code>0.5</code> 表示质量降低到原始的 50%。</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">最大比例值。通常等于 <code>1.0</code>（100% 质量），这是级别 0 的默认值。</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">对渲染的视觉影响（<code>Low</code>、<code>Medium</code>、<code>High</code>）。插件会系统地优先提高具有 <code>Low</code> 影响的缩放器的级别（降低质量）。</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">指定缩放器优化的子系统（<code>CPU</code>、<code>GPU</code> 或两者）。如果当前系统瓶颈是 <code>CPU</code>，则插件将忽略 <code>GPU</code>-缩放器。</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">某些专用的缩放器（<code>WebResolutionScaler</code>、<code>WebCameraClipScaler</code>、<code>WebLayerCullingScaler</code>）会将其设置应用于场景中的特定相机，而不是全局应用。</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">使用相机标签 (Camera Tags)</p><p>这些缩放器不使用 <code>Camera.main</code> 调用。相反，它们使用 <code>Target Tags</code> 数组扫描活动的相机。</p><p>默认情况下，那里指定了 <code>MainCamera</code> 标签。<strong>如果您的游戏使用自定义相机标签（例如 <code>PlayerCamera</code>），则必须将它们添加到缩放器设置中。</strong> 否则，这些相机的缩放将无法触发。</p></div><h2 id="开发设置" tabindex="-1">开发设置 <a class="header-anchor" href="#开发设置" aria-label="Permalink to &quot;开发设置&quot;">​</a></h2><p>此部分专门用于调试浏览器或编辑器中的插件行为。</p><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">启用将插件操作的详细日志记录到浏览器（或 Unity）控制台。输出关于瓶颈转移、缩放器激活和 Anti Yo-Yo 惩罚系统触发的消息。</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">优化</p><p>日志记录利用内部的 <code>DebugWebAP</code> 包装器。强烈建议在最终发布 (Production) 构建中禁用 <code>Logging</code>，以节省资源并保持控制台清洁。</p></div>',19)])])}const b=a(r,[["render",n]]);export{y as __pageData,b as default};
